import zipfile
import xml.etree.ElementTree as ET
import re

pptx_path = '/var/folders/zb/gv9h0w894b92wzw6hwsqc0pr0000gn/T/apex_eval_32__s9uc6n7/DV02 EU Company Renewables Percentages.pptx'

def extract_text_from_xml(xml_content):
    # Remove namespaces for easier parsing
    xml_content = re.sub(r'\s+xmlns="[^"]*"', '', xml_content)
    try:
        root = ET.fromstring(xml_content)
        # Find all text elements
        text_elements = []
        for elem in root.iter():
            if elem.text and elem.text.strip():
                text_elements.append(elem.text.strip())
            if elem.tail and elem.tail.strip():
                text_elements.append(elem.tail.strip())
        return ' '.join(text_elements)
    except Exception as e:
        return f'Error parsing XML: {e}'

try:
    with zipfile.ZipFile(pptx_path, 'r') as zip_ref:
        # Extract all slide content
        for slide_file in [f for f in zip_ref.namelist() if 'ppt/slides/slide' in f]:
            content = zip_ref.read(slide_file).decode('utf-8')
            text = extract_text_from_xml(content)
            if text and len(text) > 10:  # Only show substantial content
                print(f'--- Slide {slide_file} ---')
                print(text[:1000])
                print()

except Exception as e:
    print(f'Error: {e}')
